import { useEffect } from "react";
import { useLocation } from "react-router-dom";
import CameraView from "./CameraView";
import PreLiveView from "./PreLiveView";
import LiveAction from "./LiveAction";
import LiveExitPopup from "./LiveExitPopup";
import { useLive, LiveState, getLiveStoreState } from "@/hooks/useLive";
import { useMissCall } from "@/hooks/useMissCall";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

export default function Live() {
  const { liveState, isExitPopupVisible, changeLiveState, setFloatingVisible, endLive, keepEarning } = useLive();
  const { getMissedCall } = useMissCall();
  const { pathname } = useLocation();

  // 状态初始化（只执行一次）
  useEffect(() => {
    if (liveState === LiveState.None) {
      changeLiveState(LiveState.Preview);
    }

    return () => {
      const { liveState: currentState } = getLiveStoreState();
      if (currentState !== LiveState.Action) {
        changeLiveState(LiveState.None);
      } else {
        setFloatingVisible(true);
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // 每次切回 Live tab：隐藏浮窗 + 埋点 + 回拨检查
  useEffect(() => {
    if (pathname !== "/live") return;
    setFloatingVisible(false);
    bpTrack(EventName.pwa_live_page_show);
    void getMissedCall("enter_live");
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pathname]);

  return (
    <>
      <div className="relative w-full h-full">
        <CameraView />
        {liveState !== LiveState.Action ? <PreLiveView /> : <LiveAction />}
      </div>

      {isExitPopupVisible && <LiveExitPopup onEndLive={endLive} onKeepEarning={keepEarning} />}
    </>
  );
}
